private static PixelBuffer GeneratePlaceholder(int width, int height, int seed, string prompt)
{
    var buf = new PixelBuffer(width > 0 ? width : 64, height > 0 ? height : 64);
    var rng = new Random(seed);
    float r = (float)rng.NextDouble() * 0.4f + 0.3f;
    float g = (float)rng.NextDouble() * 0.4f + 0.2f;
    float b = (float)rng.NextDouble() * 0.4f + 0.3f;
    for (var y = 0; y < buf.Height; y++)
        for (var x = 0; x < buf.Width; x++)
            buf.SetPixel(x, y, r + (float)rng.NextDouble() * 0.1f, g + (float)rng.NextDouble() * 0.1f, b + (float)rng.NextDouble() * 0.1f, 1f);
    return buf;
}
